import{j as r,b as t,c as o,aa as n}from"./chunks/framework.DDeudtUa.js";const a="/assets/jvm-3.B-lODpB_.png",s="/assets/jvm-4.ChLqkr_F.png",i="/assets/mysql查询流程.BUGLa-RC.png",l="/assets/redis-10434dc7-c7a3-4c1a-b484-de3fb37669ee.BXCcN6n7.png",y=JSON.parse('{"title":"九阳真经","description":"","frontmatter":{"title":"九阳真经","date":"2001-03-01T00:00:00.000Z","tags":["九阳真经"],"categories":["九阳真经"]},"headers":[],"relativePath":"ZhenJing/九阳真经.md","filePath":"ZhenJing/九阳真经.md","lastUpdated":null}'),e={name:"ZhenJing/九阳真经.md"},g=n(`<h1 id="九阳真经" tabindex="-1">九阳真经 <a class="header-anchor" href="#九阳真经" aria-label="Permalink to &quot;九阳真经&quot;">​</a></h1><h2 id="java基础" tabindex="-1">Java基础 <a class="header-anchor" href="#java基础" aria-label="Permalink to &quot;Java基础&quot;">​</a></h2><h3 id="object-类" tabindex="-1">Object 类 <a class="header-anchor" href="#object-类" aria-label="Permalink to &quot;Object 类&quot;">​</a></h3><h4 id="object-类的方法" tabindex="-1">Object 类的方法 <a class="header-anchor" href="#object-类的方法" aria-label="Permalink to &quot;Object 类的方法&quot;">​</a></h4><p>Java 中所有的类都是 Object 类的子类，Object 类的方法大致可以分为 6 类，主要提供了 11 个方法：</p><ul><li>对象比较：hashCode()、equals(Object obj)</li><li>对象拷贝：clone()</li><li>对象转字符串：toString()</li><li>多线程调度：wait()、wait(long timeout)、wait(long timeout, int nanos)、notify()、notifyAll()</li><li>反射：getClass()</li><li>垃圾回收：finalize()</li></ul><h3 id="集合框架" tabindex="-1">集合框架 <a class="header-anchor" href="#集合框架" aria-label="Permalink to &quot;集合框架&quot;">​</a></h3><h4 id="有哪些集合" tabindex="-1">有哪些集合 <a class="header-anchor" href="#有哪些集合" aria-label="Permalink to &quot;有哪些集合&quot;">​</a></h4><p>主要分为两条大的支线：</p><ul><li><p><strong>Collection 接口</strong>：主要有三个子接口：</p><ul><li><code>List</code>：一个有序的集合，可以包含重复的元素。实现类包括 ArrayList、LinkedList 等。</li><li><code>Set</code>：一个不包含重复元素的集合。实现类包括 HashSet、LinkedHashSet、TreeSet 等。</li><li><code>Queue</code>：一个用于保持元素 <strong>队列</strong> 的集合。实现类包括 PriorityQueue、ArrayDeque 等。</li></ul></li><li><p><strong>Map 接口</strong>：表示键值对的集合。实现类包括 HashMap、LinkedHashMap、TreeMap 等。</p></li></ul><h4 id="有哪些是线程安全的集合" tabindex="-1">有哪些是线程安全的集合 <a class="header-anchor" href="#有哪些是线程安全的集合" aria-label="Permalink to &quot;有哪些是线程安全的集合&quot;">​</a></h4><ul><li><p><strong>CopyOnWriteArrayList</strong></p><p>CopyOnWriteArrayList 是线程安全的 <strong>ArrayList</strong>。</p><p>它的名字叫 CopyOnWritt —— 写时复制，已经明示了它的原理。</p><p>CopyOnWriteArrayList 允许并发读，读操作是无锁的，性能较高。</p><p>至于写操作，比如向容器中添加一个元素，则首先将当前容器复制一份，然后在新副本上执行加锁的写操作，结束之后再将原容器的引用指向新容器。</p></li><li><p><strong>Hashtable</strong></p><p>Hashtable 是线程安全的 <strong>HashMap</strong>，它是直接在 HashMap 的方法上加 synchronized 关键字，但这样会降低性能，现在已经不推荐使用。</p></li><li><p><strong>ConcurrentHashMap</strong></p><p>ConcurrentHashmap 也是线程安全的 <strong>HashMap</strong>，是官方推荐使用的。</p><p>在1.7 版本里它是基于 <strong>分段锁</strong> 实现的，在 1.8 之后是基于 CAS 和 synchronized 实现的。</p></li></ul><h4 id="concurrenthashmap-的实现" tabindex="-1">ConcurrentHashmap 的实现 <a class="header-anchor" href="#concurrenthashmap-的实现" aria-label="Permalink to &quot;ConcurrentHashmap 的实现&quot;">​</a></h4><p>1.7 版本的 ConcurrentHashMap 采用分段锁机制，里面包含一个 <strong>段数组</strong>，每个段都是一个 HashMap，段和段之间相互不会受到并发影响，也就是说锁的细粒度更高了。</p><p>1.8 之后 ConcurrentHashMap 实现线程安全不是在数据结构上下功夫，它的数据结构和 HashMap 是一样的，都是：数组+链表+红黑树。</p><p>它实现线程安全的关键点在于 put 流程：</p><ol><li>如果 node 是空的话，就通过 <strong>CAS + 自旋</strong> 的方式写入</li><li>其他情况下会采用 <strong>CAS + synchronized</strong> 实现</li><li>CAS 操作由处理器来保证原子性，它是一种乐观锁，不会阻塞线程，而是在更新时检查是否有其他线程已经修改了数据，如果没有就更新，如果有就重试。</li></ol><h3 id="stream-流" tabindex="-1">Stream 流 <a class="header-anchor" href="#stream-流" aria-label="Permalink to &quot;Stream 流&quot;">​</a></h3><p>Stream 流提供了一种高级迭代模式，主要用于对集合进行复杂的筛选、转换和收集操作，并且流操作是延迟执行的，这意味着它们只在必要的时候才会计算。</p><p>同时 Stream 也支持并行操作，这样可以利用到多核处理器的能力，使得操作变得更加高效。</p><h3 id="lambda-表达式" tabindex="-1">Lambda 表达式 <a class="header-anchor" href="#lambda-表达式" aria-label="Permalink to &quot;Lambda 表达式&quot;">​</a></h3><p>Lambda 表达式本质上是一段 <strong>匿名内部类</strong>，也可以是一段可以传递的代码。</p><p>比如我们以前使用 Runnable 创建并运行线程：</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Thread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Runnable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Override</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        System.out.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">println</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Thread is running before Java8!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">start</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>这是通过内部类的方式来重写 run 方法，使用 Lambda 表达式，可以<strong>使得代码可以更加简洁</strong>：</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Thread</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( () </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> System.out.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">println</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Thread is running since Java8!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) ).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">start</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>但是，只有那些函数式接口才能缩写成 Lambda 表示式，也就是说，接口里只能包含一个抽象方法。</p><h3 id="反射机制" tabindex="-1">反射机制 <a class="header-anchor" href="#反射机制" aria-label="Permalink to &quot;反射机制&quot;">​</a></h3><h4 id="反射是什么" tabindex="-1">反射是什么 <a class="header-anchor" href="#反射是什么" aria-label="Permalink to &quot;反射是什么&quot;">​</a></h4><p>我们经常利用 <code>new</code> 方式来创建对象实例，这种方式在 <strong>编译</strong> 时就确定了类型信息。</p><p>而如果，我们想在代码运行的时候动态地获取类信息、创建类实例、调用类方法这时候就要用到 <strong>反射</strong>。</p><p>通过反射我们可以获取任意一个类的所有属性和方法，还可以调用这些方法和属性。</p><p>反射最核心的四个类：</p><ul><li>Class 类：获取类信息</li><li>Field 类：获取类的属性信息</li><li>Constructor 类：获取类的构造方法信息</li><li>Method 类：获取类的方法信息</li></ul><h4 id="反射的应用场景" tabindex="-1">反射的应用场景 <a class="header-anchor" href="#反射的应用场景" aria-label="Permalink to &quot;反射的应用场景&quot;">​</a></h4><p>一般我们在写业务代码的时候，很少会接触到直接使用反射机制的场景。</p><p>但是，这并不代表反射没有用。相反，正是因为反射，我们才能这么轻松地使用各种框架。像 Spring、MyBatis 等等框架中都大量使用了反射机制。</p><p>Spring 里的很多 <strong>注解</strong> ，它真正的实现原理就是利用反射。</p><p>就像我们使用 Spring 的时候 ，一个 <code>@Component</code> 注解就声明了一个类为 Bean，一个 <code>@Value</code> 注解就读取到了配置文件中的值。</p><p>这些都是因为代码在运行过程中可以基于 <strong>反射</strong> 来获取到类，读取到类/属性/方法/方法的参数上的注解，进而执行一些特定的操作。</p><p>注解这里就有两个作用：</p><ul><li><p>一是标记我们要进行相应处理的类/属性/方法；</p></li><li><p>二是注解本身带有处理信息，可以参与到处理逻辑中。</p></li></ul><h4 id="反射的原理" tabindex="-1">反射的原理 <a class="header-anchor" href="#反射的原理" aria-label="Permalink to &quot;反射的原理&quot;">​</a></h4><p>Java 程序的执行分为 <strong>编译</strong> 和 <strong>运行</strong> 两步，编译之后会生成字节码(.class)文件，JVM 进行类加载的时候，会加载字节码文件，将类型相关的所有信息加载进方法区。反射就是在运行的时候，去获取这些方法区的类信息，然后进行各种操作。</p><h4 id="反射的优点和缺点" tabindex="-1">反射的优点和缺点 <a class="header-anchor" href="#反射的优点和缺点" aria-label="Permalink to &quot;反射的优点和缺点&quot;">​</a></h4><p>优点：</p><ol><li><strong>灵活性</strong>：反射提供了一种机制，允许程序在运行时动态地修改对象的属性和方法，从而提高了程序的灵活性和可扩展性，避免将程序写死到代码里。这让我们可以通过修改配置来实现一些原本需要修改代码的操作</li><li><strong>动态代理</strong>：反射机制是实现动态代理的基础，使得可以在运行时动态地创建代理类和对象，广泛用于 spring AOP 的场景。</li></ol><p>缺点：</p><ol><li><strong>性能开销</strong>：反射操作相比直接的 Java 方法调用要慢得多，因为它涉及到类型解析、方法调用等动态处理过程。</li><li><strong>安全风险</strong>：反射可以用来访问类的私有成员和方法，这可能会破坏封装原则，增加安全风险。</li></ol><h2 id="并发编程" tabindex="-1">并发编程 <a class="header-anchor" href="#并发编程" aria-label="Permalink to &quot;并发编程&quot;">​</a></h2><h3 id="inheritablethreadlocal" tabindex="-1">InheritableThreadLocal <a class="header-anchor" href="#inheritablethreadlocal" aria-label="Permalink to &quot;InheritableThreadLocal&quot;">​</a></h3><p>ThreadLocal 是 Java 提供的一种用于实现 <strong>线程局部变量</strong> 的工具类。它允许每个线程都拥有自己的独立变量副本，从而实现线程隔离，用于解决多线程中共享对象的线程安全问题。</p><ul><li>每个线程都拥有一个和 HashMap 结构类似的 ThreadLocalMap，用于存储与该线程相关的 ThreadLocal 变量。</li><li>ThreadLocalMap 内部维护着对象数组，key 是 ThreadLocal 的弱引用，value 是 ThreadLocal 的泛型值。</li><li>每个线程在往 ThreadLocal 里设置值的时候，都是往自己的 ThreadLocalMap 里存，读也是以某个 ThreadLocal 作为引用，在自己的 ThreadLocalMap 里找对应的 key，从而实现了线程隔离。</li></ul><p>但 ThreadLocal 不支持父线程和子线程之间的值传递。</p><p>为了解决这个问题，Java 扩展了 ThreadLocal 类，提供了 InheritableThreadLocal 类。</p><p>它在创建子线程时会将父线程的 <strong>本地变量的值</strong> 复制给子线程，这一特性使得在父线程可以给子线程间传递数据。</p><h4 id="threadlocal-的缺点" tabindex="-1">ThreadLocal 的缺点 <a class="header-anchor" href="#threadlocal-的缺点" aria-label="Permalink to &quot;ThreadLocal 的缺点&quot;">​</a></h4><p><strong>内存泄露</strong>：最常见的问题之一是内存泄露。<code>ThreadLocal</code> 变量存储在每个 <code>Thread</code> 对象的 <code>ThreadLocalMap</code> 中。如果线程执行完毕但未被回收，而<code>ThreadLocal</code> 变量又未被显式移除，那么这些变量以及它们引用的对象就不会被垃圾回收器回收，导致内存泄露。</p><p>特别是在使用线程池时，由于线程通常会被重用，所以 <code>ThreadLocal</code> 变量可能会一直保留，增加内存泄露的风险。</p><h3 id="synchronized" tabindex="-1">synchronized <a class="header-anchor" href="#synchronized" aria-label="Permalink to &quot;synchronized&quot;">​</a></h3><p>synchronized 可以用来保证代码的原子性。</p><h4 id="synchronized-的用法" tabindex="-1">synchronized 的用法 <a class="header-anchor" href="#synchronized-的用法" aria-label="Permalink to &quot;synchronized 的用法&quot;">​</a></h4><ul><li><p><strong>修饰实例方法</strong>：作用于当前对象实例加锁，进入同步代码前要获得 <strong>当前对象实例的锁</strong></p></li><li><p><strong>修饰静态方法</strong>：也就是给当前类加锁，会作⽤于类的所有对象实例 ，进⼊同步代码前要获得当前 class 的锁。因为静态成员不属于任何⼀个实例对象，是类成员。</p><p>如果⼀个线程 A 调⽤⼀个实例对象的⾮静态 synchronized ⽅法，⽽线程 B 需要调⽤这个实例对象所属类的静态 synchronized ⽅法，是允许的，不会发⽣互斥现象，因为访问静态 synchronized ⽅法占⽤的锁是当前类的锁，⽽访问⾮静态 synchronized ⽅法占⽤的锁是当前实例对象锁。</p></li><li><p><strong>修饰代码块</strong> ：指定加锁对象，对给定对象/类加锁。 synchronized(this|object) 表示进⼊同步代码库前要获得给定对象的锁。 synchronized(类.class) 表示进⼊同步代码前要获得 当前 <strong>class</strong> 的锁</p></li></ul><h3 id="同步器-aqs" tabindex="-1">同步器 AQS <a class="header-anchor" href="#同步器-aqs" aria-label="Permalink to &quot;同步器 AQS&quot;">​</a></h3><p>AbstractQueuedSynchronizer 抽象同步队列，简称 AQS ，它是 Java 并发包的根基，并发包中的锁就是基于 AQS 实现的。</p><h4 id="aqs-核心思想" tabindex="-1">AQS 核心思想 <a class="header-anchor" href="#aqs-核心思想" aria-label="Permalink to &quot;AQS 核心思想&quot;">​</a></h4><p>AQS 核心思想是，如果被请求的资源空闲，则将当前请求资源的线程设置为有效的工作线程，并且将资源设置为锁定状态。</p><p>如果被请求的资源被占用，那么就需要一套线程阻塞等待以及被唤醒时分配锁的机制，这个机制 AQS 是基于一个双向队列和一个共享变量实现的。</p><p>AQS 使用 volatile 修饰的 <strong>int 变量 state 来控制同步状态</strong>，用于展示当前资源的锁情况。</p><p>同时通过内置的 <strong>线程等待队列</strong> 来展示线程的排队情况。</p><p>暂时获取不到锁的线程将被加入到该线程等待队列中，自旋一定次数后，会将线程阻塞，并等待锁的分配。</p><p>以 ReentrantLock 为例，state 初始值为 0，表示未锁定状态。</p><p>A 线程独占该锁时会将 state + 1。此后，其他线程再尝试获得锁就会失败，直到 A 线程释放锁，并令 state = 0 ，其它线程才有机会获取该锁。</p><p>此外，在释放锁之前，A 线程自己是可以重复获取此锁的（state 会累加），这就是可重入的概念。</p><p>但要注意，获取多少次就要释放多少次，这样才能保证 state 是能回到零态的。</p><h3 id="reentrantlock" tabindex="-1">ReentrantLock <a class="header-anchor" href="#reentrantlock" aria-label="Permalink to &quot;ReentrantLock&quot;">​</a></h3><h4 id="reentrantlock-是什么-实现原理" tabindex="-1">ReentrantLock 是什么，实现原理 <a class="header-anchor" href="#reentrantlock-是什么-实现原理" aria-label="Permalink to &quot;ReentrantLock 是什么，实现原理&quot;">​</a></h4><p>ReentrantLock 实现了 Lock 接口，是一个可重入且独占式的锁，和 synchronized 关键字类似。</p><p>可重入表示当前线程获取该锁后再次获取不会被阻塞，也就意味着同一个线程可以多次获得同一个锁而不会发生死锁。</p><p>相比 Synchronized，ReentrantLock 更灵活、更强大，增加了公平锁和非公平锁等高级功能。</p><p>在内部，ReentrantLock 利用了 AQS 框架来实现锁的功能。</p><p>此处讲【AQS 核心思想】。</p><h4 id="synchronized-和-reentrantlock-的对比" tabindex="-1">synchronized 和 ReentrantLock 的对比 <a class="header-anchor" href="#synchronized-和-reentrantlock-的对比" aria-label="Permalink to &quot;synchronized 和 ReentrantLock 的对比&quot;">​</a></h4><p><strong>两者都是可重入锁</strong></p><ul><li><strong>可重入锁</strong> 也叫递归锁，指的是线程可以再次获取自己的内部锁。比如一个线程获得了某个对象的锁，此时这个对象锁还没有释放，当其再次想要获取这个对象的锁的时候还是可以获取的，如果是不可重入锁的话，就会造成死锁。</li></ul><p><strong>synchronized 隐式锁 而 ReentrantLock 是显式锁</strong></p><ul><li><p><code>synchronized</code> 是依赖于 JVM 实现的，它对于对象监视器的加锁解锁都是在虚拟机层面实现的，并没有直接暴露给我们，属于 <strong>隐式锁</strong>。</p></li><li><p><code>ReentrantLock</code> 则需要手动执行 <strong>加锁</strong> 和 <strong>解锁</strong> 方法，属于 <strong>显式锁</strong>。</p></li></ul><p><strong>ReentrantLock 比 synchronized 增加了一些高级功能</strong></p><ul><li><strong>等待可中断</strong> : <code>ReentrantLock</code>提供了一种能够中断等待锁的线程的机制，也就是说正在等待的线程可以选择放弃等待，改为处理其他事情，而<code>synchronized</code> 不行。</li><li><strong>可实现公平锁</strong> : <code>ReentrantLock</code>可以指定是公平锁还是非公平锁。而<code>synchronized</code>只能是非公平锁。</li><li><strong>可实现选择性通知（锁可以绑定多个条件）</strong>: <code>synchronized</code> 关键字与 <code>wait()</code>和<code>notify()</code>/<code>notifyAll()</code>方法相结合可以实现等待/通知机制。而 <code>ReentrantLock</code> 借助于 <code>Condition</code> 接口可以创建更多的等待通知条件，细粒度更高。</li></ul><h4 id="公平锁和非公平锁" tabindex="-1">公平锁和非公平锁 <a class="header-anchor" href="#公平锁和非公平锁" aria-label="Permalink to &quot;公平锁和非公平锁&quot;">​</a></h4><ul><li><strong>公平锁</strong> : 锁被释放之后，最先进入等待队列的线程才能先得到锁。性能较差一些，因为公平锁为了保证时间上的绝对顺序，上下文切换更频繁，但是可以避免线程饥饿的情况发生。</li><li><strong>非公平锁</strong> ：锁被释放之后，后请求锁的线程可能会先获取到锁，也就是可以插队。这种做法性能更好，因为它的吞吐量比较大，但可能会导致某些线程永远无法获取到锁。</li></ul><h4 id="可中断锁和不可中断锁" tabindex="-1">可中断锁和不可中断锁 <a class="header-anchor" href="#可中断锁和不可中断锁" aria-label="Permalink to &quot;可中断锁和不可中断锁&quot;">​</a></h4><ul><li><strong>可中断锁</strong> ：获取锁的过程中可以被中断，不需要一直等到获取锁之后 才能进行其他逻辑处理。<code>ReentrantLock</code> 就属于是可中断锁。</li><li><strong>不可中断锁</strong> ：一旦线程申请了锁，就只能等到拿到锁以后才能进行其他的逻辑处理。 <code>synchronized</code> 就属于是不可中断锁。</li></ul><h3 id="线程池" tabindex="-1">线程池 <a class="header-anchor" href="#线程池" aria-label="Permalink to &quot;线程池&quot;">​</a></h3><h4 id="使用线程池的好处" tabindex="-1">使用线程池的好处 <a class="header-anchor" href="#使用线程池的好处" aria-label="Permalink to &quot;使用线程池的好处&quot;">​</a></h4><ul><li><strong>节约系统资源</strong>：频繁地创建和销毁线程会消耗系统资源，线程池能够复用已创建的线程。</li><li><strong>提高响应速度</strong>：当任务到达时，任务可以不需要等待线程创建就立即执行。</li><li><strong>功能丰富</strong>：线程池支持定时执行、周期性执行、单线程执行和并发数控制等功能。</li></ul><h4 id="线程池的主要参数" tabindex="-1">线程池的主要参数 <a class="header-anchor" href="#线程池的主要参数" aria-label="Permalink to &quot;线程池的主要参数&quot;">​</a></h4><ul><li><strong>核心线程数</strong>：即使这些线程处于空闲状态，它们也不会被回收。这是线程池保持在等待状态下的线程数。</li><li><strong>最大线程数</strong>：当 <strong>等待队列</strong> 满了之后，线程池会创建新线程来处理任务，直到线程数达到这个最大值。</li><li><strong>非核心线程最大空闲存活时间</strong>：如果线程池中的线程数量超过了 <strong>最大线程数</strong>，那么这些多余的线程在空闲时间超过这个值的时候会被回收。</li><li><strong>非核心线程最大空闲存活时间的单位</strong>：上一个参数的时间单位。</li><li><strong>等待队列</strong>：一个用于存放 <strong>待处理任务</strong> 的阻塞队列。当所有 <strong>核心线程</strong> 都忙碌的时候，新任务会被放在这个队列里等待执行。</li><li><strong>线程创建工厂</strong>：用于创建线程池中的线程。</li><li><strong>拒绝策略</strong>：定义了当线程已经达到 <strong>最大线程数</strong>，而 <strong>工作队列</strong> 也已经饱和之后，对新任务的处理策略。常见的拒绝策略包括：抛出异常、直接丢弃、丢弃队列中最老的任务、由提交任务的线程来直接执行任务等。</li></ul><h4 id="线程池的拒绝策略有哪些" tabindex="-1">线程池的拒绝策略有哪些 <a class="header-anchor" href="#线程池的拒绝策略有哪些" aria-label="Permalink to &quot;线程池的拒绝策略有哪些&quot;">​</a></h4><ul><li><strong>抛出异常</strong>：这是默认的拒绝策略。此时会抛出一个异常，并拒绝执行新任务。</li><li><strong>直接丢弃</strong>：该策略会默默地丢弃被拒绝的任务，不做任何处理也不抛出异常。</li><li><strong>丢弃队列中最老的任务</strong>：该策略会丢弃队列中等待最久的任务，然后尝试重新提交被拒绝的任务。</li><li><strong>由提交任务的线程来直接执行任务</strong>：该策略不会抛出异常，而是会让 <strong>提交任务的线程</strong> 自己来执行这个任务。</li></ul><h4 id="线程池的工作流程" tabindex="-1">线程池的工作流程 <a class="header-anchor" href="#线程池的工作流程" aria-label="Permalink to &quot;线程池的工作流程&quot;">​</a></h4><ol><li>线程池刚创建时，里面没有一个线程。<strong>任务队列</strong> 是作为参数传进来的。不过，就算队列里面有任务，线程池也不会马上执行它们。</li><li>当往线程池中添加一个任务时，线程池会做一些判断： <ol><li>如果正在运行的线程数量小于 <strong>核心线程数</strong>，那么由 <strong>线程创建工厂</strong> 来创建线程执行这个任务</li><li>如果正在运行的线程数量大于或等于 <strong>核心线程数</strong>，那么会将这个任务放入 <strong>等待队列</strong></li><li>如果这时候队列满了，而且正在运行的线程数量小于 <strong>最大线程数</strong>，那么就由 <strong>线程创建工厂</strong> 来创建 <strong>非核心线程</strong> 来立刻执行这个任务；</li><li>如果队列满了，而且正在运行的线程数量大于或等于 <strong>最大线程数</strong>，那么线程池会根据 <strong>拒绝策略</strong> 来对应处理。</li></ol></li></ol><h2 id="jvm" tabindex="-1">JVM <a class="header-anchor" href="#jvm" aria-label="Permalink to &quot;JVM&quot;">​</a></h2><h3 id="jvm-运行时内存区域" tabindex="-1">JVM 运行时内存区域 <a class="header-anchor" href="#jvm-运行时内存区域" aria-label="Permalink to &quot;JVM 运行时内存区域&quot;">​</a></h3><p>JVM 在执行 Java 程序时，需要在内存中分配空间来处理各种数据，这些内存区域主要包括方法区、堆、栈、程序计数器和本地方法栈。</p><p><img src="`+a+'" alt="三分恶面渣逆袭：Java虚拟机运行时数据区"></p><p>其中 <strong>方法区</strong> 和 <strong>堆</strong> 是线程共享区，<strong>虚拟机栈</strong>、<strong>本地方法栈</strong> 和 <strong>程序计数器</strong> 是线程私有的。</p><p><strong>程序计数器</strong></p><ul><li>程序计数器也被称为 PC 寄存器，是一块较小的内存空间。它可以看作是 <strong>当前线程</strong> 所执行的字节码 <strong>行号指示器</strong>，指向下一个将要执行的指令代码，由执行引擎来读取下一条指令。</li><li>更确切的说，<strong>一个线程的执行，是通过字节码解释器改变当前线程的计数器的值，来获取下一条需要执行的字节码指令，从而确保线程的正确执行</strong>。</li></ul><p><strong>Java 虚拟机栈</strong></p><ul><li>Java 虚拟机栈，通常指的就是“栈”，它的生命周期与线程相同。</li><li>Java 虚拟机栈中是一个个 <strong>栈帧</strong>，每个栈帧对应一个被调用的方法。当线程执行一个方法时，会创建一个对应的栈帧，并将栈帧压入栈中。当方法执行完毕后，将栈帧从栈中移除。</li></ul><p><img src="'+s+'" alt="三分恶面渣逆袭：Java虚拟机栈"></p><p><strong>本地方法栈</strong></p><ul><li>本地方法栈与虚拟机栈相似，区别在于虚拟机栈是为虚拟机执行 Java 方法服务的，而本地方法栈是为虚拟机使用到的本地（Native）方法服务的。</li></ul><p><strong>Java 堆</strong></p><ul><li>Java 堆是虚拟机所管理的内存中最大的一块，被所有线程共享，在虚拟机启动时创建。</li><li>以前，Java 中“几乎”所有的对象都会在堆中分配，但随着 JIT 编译器的发展和逃逸技术的逐渐成熟，所有的对象都分配到堆上渐渐变得不那么“绝对”了。</li><li>从 JDK 7 开始，Java 虚拟机已经默认开启逃逸分析了，意味着如果某些方法中的对象引用没有被返回或者未被外面使用（也就是未逃逸出去），那么对象可以直接在栈上分配内存。</li><li>Java 堆是 <strong>垃圾收集器</strong> 管理的内存区域，因此一些资料中它也被称作“GC 堆”（Garbage Collected Heap）。</li><li>从回收内存的角度来看，由于垃圾收集器大部分都是基于分代收集理论设计的，所以 Java 堆中经常会出现 新生代 、老年代、Eden空间、From Survivor空间、To Survivor空间 等名词。</li></ul><p><strong>方法区</strong></p><ul><li>方法区是一块比较特别的区域，和堆类似，也是各个线程共享的内存区域，用于存储已被虚拟机加载的类型信息、常量、静态变量、即时编译器编译后的代码缓存等。</li><li>Java 虚拟机规范对它的约束非常宽松，所以方法区的具体实现历经了许多变迁，例如 JDK 1.7 时，方法区被永久代所代替，而在 JDK 1.8 时，永久代被彻底移除，取而代之的是元空间。</li></ul><h4 id="堆和栈的区别" tabindex="-1"><strong>堆和栈的区别</strong> <a class="header-anchor" href="#堆和栈的区别" aria-label="Permalink to &quot;**堆和栈的区别**&quot;">​</a></h4><ul><li>堆属于线程共享的内存区域，<strong>几乎</strong> 所有的对象都在对上分配，生命周期不由单个方法调用所决定，可以在方法调用结束后继续存在，直到不在被任何变量引用，然后被 <strong>垃圾收集器</strong> 回收。</li><li>栈就是前面提到的 JVM 栈（主要存储局部变量、方法参数、对象引用等），属于线程私有，通常随着方法调用的结束而消失，也就无需进行垃圾收集。</li></ul><h3 id="垃圾回收机制" tabindex="-1">垃圾回收机制 <a class="header-anchor" href="#垃圾回收机制" aria-label="Permalink to &quot;垃圾回收机制&quot;">​</a></h3><h4 id="垃圾判断算法" tabindex="-1">垃圾判断算法 <a class="header-anchor" href="#垃圾判断算法" aria-label="Permalink to &quot;垃圾判断算法&quot;">​</a></h4><p>JVM 在做垃圾回收之前，需要先搞清楚什么是垃圾，什么不是垃圾，那么就需要一种垃圾判断算法，通常有 <strong>引用计数算法</strong> 和 <strong>可达性分析算法</strong>。</p><p><strong>引用计数算法</strong>：是通过在对象头中分配一个空间来保存该对象被引用的次数，当次数为 0 的时候，说明此对象是可以回收的。</p><p><strong>可达性分析算法</strong>：是通过一些被称为 <strong>GC Roots</strong> 的对象作为起点，然后向下搜索，当一个对象到 <strong>GC Roots</strong> 之间没有任何引用相连时，证明此对象不可达，是可以回收的。</p><p>在确定了哪些垃圾可以被回收后，垃圾收集器要做的事情就是进行垃圾回收，这里面就涉及到垃圾收集算法。</p><h4 id="垃圾收集有哪些算法-各自的特点" tabindex="-1">垃圾收集有哪些算法，各自的特点 <a class="header-anchor" href="#垃圾收集有哪些算法-各自的特点" aria-label="Permalink to &quot;垃圾收集有哪些算法，各自的特点&quot;">​</a></h4><p>常见的垃圾收集算法主要分为 3 类：</p><ol><li><strong>标记-清除算法</strong>：首先标记出所有不需要回收的对象，在标记完成后统一回收掉所有没有被标记的对象。缺点是：<strong>标记清除后会产生大量不连续的内存碎片，造成空间浪费。</strong></li><li><strong>标记-复制算法</strong>：将可用内存按容量划分为大小相等的两块，每次只使用其中的一块。当这一块的内存用完了，就将还存活着的对象复制到另外一块上面，然后再把已使用过的内存空间一次性清理掉。缺点是：<strong>可用内存只有原来的一半，而且复制性能不佳</strong></li><li><strong>标记-整理算法</strong>：其中的标记过程仍然与“标记-清除”算法一样，但后续步骤不是直接对可回收对象进行清理，而是让所有存活的对象都向内存空间一端移动，然后直接清理掉边界以外的内存。缺点是：<strong>由于多了整理这一步，因此效率也不高，适合老年代这种垃圾回收频率不是很高的场景。</strong></li></ol><p>负责执行垃圾回收的组件叫做 <strong>垃圾回收器</strong>，不同的垃圾回收器适用于不同的场景。</p><h3 id="类加载机制" tabindex="-1">类加载机制 <a class="header-anchor" href="#类加载机制" aria-label="Permalink to &quot;类加载机制&quot;">​</a></h3><h4 id="类加载的过程" tabindex="-1">类加载的过程 <a class="header-anchor" href="#类加载的过程" aria-label="Permalink to &quot;类加载的过程&quot;">​</a></h4><p>类加载的过程可以简单概括为 5 个阶段：<strong>载入、验证、准备、解析、初始化</strong>。</p><p><strong>载入</strong></p><p>载入过程主要做三件事：</p><ol><li>获取此类的二进制字节流</li><li>将这个字节流所代表的静态存储结构转化为方法区的运行时数据结构</li><li>在内存中生成一个代表这个类的 Class 对象，作为方法区中这个类对象的访问入口。</li></ol><p><strong>验证</strong></p><p>在该阶段对 class 文件中的字节流进行校验，只有符合字节码规范的才能被 JVM 正确执行。</p><p><strong>准备</strong></p><p>在该阶段对类变量（也称为静态变量，static 关键字修饰的）分配内存并初始化，对应数据类型的默认初始值，如 0、0L、null、false 等。</p><p><strong>解析</strong></p><p>解析阶段是虚拟机将常量池内的 <strong>符号引用</strong> 替换为 <strong>直接引用</strong> 的过程。解析动作主要针对类或接口、字段、类方法、接口方法、方法类型等。</p><p><strong>初始化</strong></p><p>该阶段是类加载过程的最后一步。在准备阶段，类变量已经被赋过默认初始值，而在初始化阶段，类变量将被赋值为代码期望赋的值。</p><p>换句话说，初始化阶段是执行类构造器方法的过程。</p><h4 id="类加载器有哪些" tabindex="-1">类加载器有哪些 <a class="header-anchor" href="#类加载器有哪些" aria-label="Permalink to &quot;类加载器有哪些&quot;">​</a></h4><p>主要有四种类加载器:</p><ul><li><strong>启动类加载器</strong>：用来加载 java 核心类库，无法被 java 程序直接引用。</li><li><strong>扩展类加载器</strong>：用来加载 Java 的扩展库。Java 虚拟机的实现会提供一个扩展库目录。该类加载器在此目录里面查找并加载 Java 类。</li><li><strong>系统类加载器</strong>：它根据 Java 应用的类路径（CLASSPATH）来加载 Java 类。一般来说，Java 应用的类都是由它来完成加载的。</li><li><strong>用户自定义类加载器</strong>：用户通过继承 java.lang.ClassLoader 类的方式自行实现的类加载器。</li></ul><h4 id="双亲委派机制" tabindex="-1">双亲委派机制 <a class="header-anchor" href="#双亲委派机制" aria-label="Permalink to &quot;双亲委派机制&quot;">​</a></h4><p>如果一个类加载器收到了类加载的请求，它首先不会自己去尝试加载这个类，而是把这个请求委派给父类加载器去完成，每一个层次的类加载器都是如此。</p><p>因此所有的加载请求最终都应该传送到最顶层的启动类加载器中，只有当父加载器反馈自己无法完成这个加载请求时，子加载器才会尝试自己去完成加载。</p><p>这就是双亲委派机制。</p><h4 id="为什么要用双亲委派机制" tabindex="-1">为什么要用双亲委派机制 <a class="header-anchor" href="#为什么要用双亲委派机制" aria-label="Permalink to &quot;为什么要用双亲委派机制&quot;">​</a></h4><p>答案是为了保证 Java 程序的稳定运行，避免类的重复加载。</p><p>如果没有使用双亲委派模型，而是每个类加载器自行加载类的话就会出现一些问题，比如如果我们编写了一个名为 <code>java.lang.Object</code> 类，那么程序运行的时候，系统就会出现两个不同的 <code>Object</code> 类。</p><p>双亲委派模型可以保证加载的是 JRE 里的那个 <code>Object</code> 类，而不是我们写的 <code>Object</code> 类。这是因为 <strong>系统类加载器</strong> 在加载此 <code>Object</code> 类时，会委托给 <strong>扩展类加载器</strong> 去加载，而 <strong>扩展类加载器</strong> 又会委托给 <strong>系统类加载器</strong>，而 <strong>系统类加载器</strong> 发现自己已经加载过了 <code>Object</code> 类，会直接返回，以此来保证 <code>Object</code> 类 的一致性。</p><h3 id="对象创建过程" tabindex="-1">对象创建过程 <a class="header-anchor" href="#对象创建过程" aria-label="Permalink to &quot;对象创建过程&quot;">​</a></h3><ol><li><strong>类加载检查</strong>：首先检查这个对象所属的类是否已经被成功加载过。如果类还没有被加载到 JVM 中，那么 JVM 会先通过类加载器加载该类。</li><li><strong>分配内存</strong>：一旦类检查通过，接下来JVM为新对象分配内存。内存分配方式主要有 <strong>指针碰撞</strong> 和 <strong>空闲列表</strong> 这两种。</li><li><strong>初始化零值</strong>：内存分配完成后，JVM会将分配的内存空间都初始化为零值（不包括对象头），这样可以保证对象的属性在代码中可以不赋初始值直接使用，保证了安全性。</li><li><strong>设置对象头</strong>：接下来设置对象头，请求头里包含了对象是哪个类的实例、如何才能找到类的元数据信息、对象的哈希码、对象的 GC 分代年龄等信息。</li><li><strong>执行构造方法</strong>：最后，JVM会执行对象的构造函数，按要求对变量进行赋值。</li></ol><h4 id="内存分配的方式" tabindex="-1">内存分配的方式 <a class="header-anchor" href="#内存分配的方式" aria-label="Permalink to &quot;内存分配的方式&quot;">​</a></h4><p>内存分配有两种方式，<strong>指针碰撞</strong>、<strong>空闲列表</strong>。</p><ul><li><strong>指针碰撞</strong>：假设 Java 堆中内存是绝对规整的，所有被使用过的内存都被放在一边，空闲的内存被放在另一边，中间放着一个指针作为分界点的指示器，那所分配内存就仅仅是把那个指针向空闲空间方向挪动一段与对象大小相等的距离，这种分配方式称为“指针碰撞”。</li><li><strong>空闲列表</strong>：如果 Java 堆中的内存并不是规整的，已被使用的内存和空闲的内存相互交错在一起，那就没有办法简单地进行指针碰撞了，虚拟机就必须维护一个列表，记录上哪些内存块是可用的，在分配的时候从列表中找到一块足够大的空间划分给对象实例，并更新列表上的记录，这种分配方式称为“空闲列表”。</li></ul><h4 id="对象创建时-堆会发生抢占吗-如何保证线程安全" tabindex="-1">对象创建时，堆会发生抢占吗？如何保证线程安全？ <a class="header-anchor" href="#对象创建时-堆会发生抢占吗-如何保证线程安全" aria-label="Permalink to &quot;对象创建时，堆会发生抢占吗？如何保证线程安全？&quot;">​</a></h4><p>为了处理并发情况下的内存分配，JVM可能会采用 <strong>线程本地分配缓冲区</strong>（TLAB）机制，即为每个线程预先分配一小块内存，这样每个线程在创建新对象时可以在自己的缓冲区上分配，减少了线程之间的竞争。</p><h2 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to &quot;MySQL&quot;">​</a></h2><h3 id="select-语句的执行流程" tabindex="-1">select 语句的执行流程 <a class="header-anchor" href="#select-语句的执行流程" aria-label="Permalink to &quot;select 语句的执行流程&quot;">​</a></h3><p><img src="'+i+'" alt="img"></p><p>MySQL 的架构共分为两层：<strong>服务层和存储引擎层</strong>。服务器层负责建立连接、分析和执行 SQL，存储引擎层负责数据的存储和提取。</p><p>因此，执行一条 SQL 查询语句时：</p><ol><li>先由 <strong>连接器</strong> 来建立客户端的连接，校验用户的身份</li><li>再 <strong>查询缓存</strong>，查询语句如果命中了缓存则直接返回数据，否则继续往下执行。MySQL 如今已删除了此模块</li><li>之后由 <strong>解析器</strong> 对 SQL 查询语句进行词法分析、语法分析，构建出语法树，方便后续模块读取表名、字段等数据</li><li>紧接着开始 <strong>执行 SQL</strong>，这里又分为了三个阶段： <ol><li>首先由 <strong>预处理器</strong> 检查表和字段是否存在，并且将语句中的星号扩展为表上的所有列。</li><li>然后由 <strong>优化器</strong> 基于查询成本的考虑来制订执行计划，比如是否使用索引，以及使用哪个索引。</li><li>最后是 <strong>执行器</strong> 根据执行计划来执行语句，从存储引擎中读取数据，返回给客户端。</li></ol></li></ol><h3 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to &quot;索引&quot;">​</a></h3><h4 id="索引的分类" tabindex="-1">索引的分类 <a class="header-anchor" href="#索引的分类" aria-label="Permalink to &quot;索引的分类&quot;">​</a></h4><ul><li>按 <strong>数据结构</strong> 分类：<strong>B+树索引、全文索引</strong></li><li>按 <strong>物理存储</strong> 分类：<strong>聚簇索引（主键索引）、二级索引</strong></li><li>按 <strong>字段特性</strong> 分类：<strong>主键索引、唯一索引、普通索引、前缀索引</strong></li><li>按 <strong>字段个数</strong> 分类：<strong>单列索引、联合索引</strong></li></ul><h4 id="为什么使用索引会加快查询" tabindex="-1">为什么使用索引会加快查询 <a class="header-anchor" href="#为什么使用索引会加快查询" aria-label="Permalink to &quot;为什么使用索引会加快查询&quot;">​</a></h4><p>我们知道数据库是存储在磁盘上的，而磁盘 I/O 是数据库操作中最耗时的部分之一。</p><p>没有索引时，数据库会进行全表扫描，这意味着它必须读取表中的每一行数据来查找匹配的行。当表的数据量非常大时，就会导致大量的磁盘 I/O 操作。</p><p>有了索引，我们就可以直接跳到索引指示的数据位置，而不必扫描整张表，从而大大减少了磁盘 I/O 操作的次数。</p><p>着就像我们通过书的目录，去查找对应的章节一样方便。</p><p>而 MySQL 的 InnoDB 存储引擎默认使用 B+ 树来作为索引的数据结构，它的查询效率非常高，时间复杂度为 <strong>O(logN)</strong>。</p><h4 id="创建索引有哪些注意点" tabindex="-1">创建索引有哪些注意点 <a class="header-anchor" href="#创建索引有哪些注意点" aria-label="Permalink to &quot;创建索引有哪些注意点&quot;">​</a></h4><p><strong>选择合适的列作为索引</strong>：</p><ul><li>如果 <strong>起不到定位的字段</strong> 通常是不需要创建索引的，因为索引的价值是快速定位，而且会占用物理空间的</li><li><strong>存在大量重复数据的字段</strong> 不需要创建索引，比如性别字段，只有男女，如果数据库表中，男女的记录分布均匀，那么无论搜索哪个值都可能得到一半的数据。在这些情况下，还不如不要索引，因为 MySQL 还有一个查询优化器，查询优化器发现某个值出现在表的数据行中的百分比很高的时候，它一般会忽略索引，进行全表扫描</li><li><strong>经常更新的字段</strong> 不用创建索引，因为索引字段频繁修改，由于要维护 B+树的有序性，那么就需要频繁的重建索引，这个过程会影响数据库性能</li></ul><p><strong>避免过多的索引</strong>：</p><ul><li>每个索引都需要占用额外的磁盘空间。而且更新表时，所有的索引都会被更新，频繁更新索引会影响数据库的性能。</li></ul><p><strong>多利用前缀索引和索引列的顺序</strong>：</p><ul><li>对于字符串类型、文本类型的列，可以考虑使用 <strong>前缀索引</strong> 来减少索引的大小。</li><li>在创建 <strong>联合索引</strong> 时，应该根据查询条件将 <strong>最常用作过滤条件的列</strong> 放在前面。</li></ul><h4 id="索引哪些情况下会失效" tabindex="-1">索引哪些情况下会失效 <a class="header-anchor" href="#索引哪些情况下会失效" aria-label="Permalink to &quot;索引哪些情况下会失效&quot;">​</a></h4><ul><li>查询条件包含 or，可能会导致索引失效</li><li>如果字段类型是字符串，where 时一定要用引号括起来，否则会因为 <strong>隐式类型转换</strong>，索引失效</li><li>like 通配符可能会导致索引失效。</li><li>联合索引，查询时的条件列不是联合索引中的第一个列，因为 <strong>违反最左匹配原则</strong> 而导致索引失效。</li><li>在索引列上使用 mysql 的内置函数时，索引失效。</li><li>对索引列运算（如，+、-、*、/），索引失效。</li><li>索引字段上使用 != 或者 &lt;&gt;，not in 时，可能会导致索引失效。</li><li>索引字段上使用 is null， is not null，可能导致索引失效。</li><li>MySQL 优化器估计使用全表扫描要比使用索引快的时候，会不使用索引。</li></ul><h4 id="索引不适合哪些场景-为什么" tabindex="-1">索引不适合哪些场景，为什么 <a class="header-anchor" href="#索引不适合哪些场景-为什么" aria-label="Permalink to &quot;索引不适合哪些场景，为什么&quot;">​</a></h4><ul><li>如果 <strong>起不到定位的字段</strong> 通常是不需要创建索引的，因为索引的价值是快速定位，而且会占用物理空间的</li><li><strong>存在大量重复数据的字段</strong> 不需要创建索引，比如性别字段，只有男女，如果数据库表中，男女的记录分布均匀，那么无论搜索哪个值都可能得到一半的数据。在这些情况下，还不如不要索引，因为 MySQL 还有一个查询优化器，查询优化器发现某个值出现在表的数据行中的百分比很高的时候，它一般会忽略索引，进行全表扫描</li><li><strong>表数据太少</strong> 的时候，不需要创建索引</li><li><strong>经常更新的字段</strong> 不用创建索引，因为索引字段频繁修改，由于要维护 B+树的有序性，那么就需要频繁的重建索引，这个过程会影响数据库性能</li></ul><h4 id="mysql-索引用的什么数据结构了解吗" tabindex="-1">MySQL 索引用的什么数据结构了解吗 <a class="header-anchor" href="#mysql-索引用的什么数据结构了解吗" aria-label="Permalink to &quot;MySQL 索引用的什么数据结构了解吗&quot;">​</a></h4><p>MySQL 的默认存储引擎是 InnoDB，它采用的是 B+ 树索引，这是一种 <strong>多叉平衡查找树</strong>，是 B 数的一种变体。它的特征有：</p><ol><li><strong>所有的值都在叶子节点</strong>：B+树的所有数据指针和值都存在于叶子节点，内部节点不存储真正的记录数据。这种结构使得在叶子节点的数据之间可以进行快速的顺序访问。</li><li><strong>叶子节点之间是相连的</strong>：B+树中的叶子节点是相互链接的，这样可以通过指针在叶子节点之间顺序遍历，这对范围查询非常高效。</li><li><strong>高利用率</strong>：由于内部节点不存储数据，B+树的每个内部节点可以拥有更多的子节点，这使得 B+ 树通常更加“矮胖”，树的高度较低，可以减少访问磁盘的次数，从而提高查询效率。</li></ol><h4 id="为什么要用-b-树-而不用二叉查找树" tabindex="-1">为什么要用 B+ 树，而不用二叉查找树 <a class="header-anchor" href="#为什么要用-b-树-而不用二叉查找树" aria-label="Permalink to &quot;为什么要用 B+ 树，而不用二叉查找树&quot;">​</a></h4><p>二叉查找树由于存在退化成链表的可能性，会使得查询操作的时间复杂度从 O(logn) 升为 O(n)。</p><p>而且会随着插入的元素越多，树的高度也越高，意味着 IO 操作的次数就越多，这会导致查询性能的严重下降，再加上不能方便地进行范围查询，所以不适合作为数据库的索引结构。</p><h4 id="为什么用-b-树而不用-b-树呢" tabindex="-1">为什么用 B+ 树而不用 B 树呢 <a class="header-anchor" href="#为什么用-b-树而不用-b-树呢" aria-label="Permalink to &quot;为什么用 B+ 树而不用 B 树呢&quot;">​</a></h4><p>B 树的每个节点都包含数据，而用户的记录数据的大小很有可能远远超过了索引数据，这导致 B 树一方面占用了太多的内存资源，另一方面在查找目标数据的时候我们会读到太多不需要的数据。</p><p>另外，如果使用 B 树来做范围查询的话，需要使用中序遍历，这会涉及多个节点的磁盘 I/O 问题，从而导致整体速度的下降。</p><h4 id="聚簇索引与非聚簇索引的区别" tabindex="-1">聚簇索引与非聚簇索引的区别 <a class="header-anchor" href="#聚簇索引与非聚簇索引的区别" aria-label="Permalink to &quot;聚簇索引与非聚簇索引的区别&quot;">​</a></h4><p>这是从物理存储的角度来区分的索引。</p><ul><li>聚簇索引就是主键索引，它的 B+ 树的叶子节点存放的是完整的实际数据</li><li>而二级索引的 B+树 的叶子节点存放的是主键值，而不是实际数据</li></ul><p>所以，如果我们查询的数据能在二级索引里直接查询到，那么就不需要回表，这个过程就是 <strong>覆盖索引</strong>。</p><p>如果查询的数据不在二级索引里，就会先检索二级索引，找到对应的叶子节点，获取到主键值后，然后再检索主键索引，才能查询到数据，这个过程就是 <strong>回表</strong>。</p><h4 id="回表" tabindex="-1">回表 <a class="header-anchor" href="#回表" aria-label="Permalink to &quot;回表&quot;">​</a></h4><p>如果查询的数据不在二级索引里，就会先检索二级索引，找到对应的叶子节点，获取到主键值后，然后再检索主键索引，才能查询到数据，这个过程就是 <strong>回表</strong>。</p><h4 id="覆盖索引" tabindex="-1">覆盖索引 <a class="header-anchor" href="#覆盖索引" aria-label="Permalink to &quot;覆盖索引&quot;">​</a></h4><p>在二级索引里面，不管是单列索引还是联合索引，如果查询数据列只用二级索引中就能够取得，不用再去查主键索引，这时候使用的索引就叫做 <strong>覆盖索引</strong>，这样就避免了回表，大大提高了效率。</p><h4 id="什么是最左前缀原则-最左匹配原则" tabindex="-1">什么是最左前缀原则/最左匹配原则 <a class="header-anchor" href="#什么是最左前缀原则-最左匹配原则" aria-label="Permalink to &quot;什么是最左前缀原则/最左匹配原则&quot;">​</a></h4><p>在 InnoDB 的 <strong>联合索引</strong> 中，查询的时候只有匹配到了前一个，才能开始匹配下一个。</p><p>根本原因是像 (a,b,c) 这样的 <strong>联合索引</strong> ，它的建树规则是先按 a 排序，在 a 相同的情况再按 b 排序，在 b 相同的情况再按 c 排序。</p><p>也就是说，<strong>b 和 c 是全局无序，局部相对有序的</strong>，这导致在没有遵循最左匹配原则的情况下，是无法利用到索引的。</p><p>因此我们平时使用或者建立联合索引的时候，要尽可能满足最左匹配原则，避免索引失效。</p><h4 id="什么是索引下推" tabindex="-1">什么是索引下推 <a class="header-anchor" href="#什么是索引下推" aria-label="Permalink to &quot;什么是索引下推&quot;">​</a></h4><p>我们知道，对于联合索引（a, b），在执行 <code>where a &gt; 1 and b = 2</code> 查询条件的时候，只有 a 字段能用到索引，那在联合索引的 B+ 树找到第一个满足条件的主键值（ID 为 2）后，还需要判断其他条件是否满足（看 b 是否等于 2），那是在联合索引里判断？还是回主键索引去判断呢？</p><ul><li>MySQL 以前，只能从 ID2 （主键值）开始一个个回表，到 <strong>主键索引</strong> 上找出数据行，再对比 b 字段值。</li><li>后来引入的 <strong>索引下推优化</strong>（index condition pushdown)， <strong>可以在联合索引遍历过程中，对联合索引中包含的字段先做判断，直接过滤掉不满足条件的记录，减少回表次数</strong>。</li></ul><p>索引下推是用于优化对二级索引的数据查询的，可以有效避免一些多余的回表操作。</p><h3 id="事务" tabindex="-1">事务 <a class="header-anchor" href="#事务" aria-label="Permalink to &quot;事务&quot;">​</a></h3><h4 id="mysql-事务的四大特性" tabindex="-1">MySQL 事务的四大特性 <a class="header-anchor" href="#mysql-事务的四大特性" aria-label="Permalink to &quot;MySQL 事务的四大特性&quot;">​</a></h4><p><strong>原子性</strong>：</p><ul><li>原子性子性意味着事务中的所有操作要么全部完成，要么全部不完成，它是不可分割的单位。如果事务中的任何一个操作失败了，整个事务都会通过 <strong>回滚日志</strong> 来回滚到事务开始之前的状态，如同这些操作从未被执行过一样。</li></ul><p><strong>一致性</strong>：</p><ul><li>一致性确保事务从一个一致的状态转换到另一个一致的状态。</li><li>比如在银行转账事务中，无论发生什么，转账前后两个账户的总金额应保持不变。假如 A 账户给 B 账户转了 10 块钱，不管成功与否，A 和 B 的总金额都不应该发生改变。</li></ul><p><strong>隔离性</strong>：</p><ul><li>隔离性意味着并发执行的事务是彼此隔离的，一个事务的执行不会被其他事务干扰。事务之间是井水不犯河水的。</li><li>隔离性主要是为了解决事务并发执行时可能出现的问题，如 <strong>脏读</strong>、<strong>不可重复读</strong>、<strong>幻读</strong> 等。</li><li>数据库通过设置 <strong>事务隔离级别</strong>（如读未提交、读已提交、可重复读、串行化）来实现事务的隔离性。</li></ul><p><strong>持久性</strong>：</p><ul><li>持久性确保事务一旦提交，它对数据库所做的更改就是永久性的，即使发生系统崩溃，数据库也能恢复到最近一次提交的状态。通常，持久性是通过数据库的 <strong>二进制日志</strong> 和 <strong>重做日志</strong> 来实现的，确保提交的事务更改不会丢失。</li></ul><h4 id="acid-靠什么保证" tabindex="-1">ACID 靠什么保证 <a class="header-anchor" href="#acid-靠什么保证" aria-label="Permalink to &quot;ACID 靠什么保证&quot;">​</a></h4><p><strong>原子性</strong></p><ul><li>主要是依靠 <strong>回滚日志</strong> 来保证：</li><li>当事务开始修改数据时，InnoDB 首先会在 <strong>回滚日志</strong> 中记录修改前的值。</li><li>如果事务中的某个操作失败或者事务被明确地回滚，InnoDB 会使用 <strong>回滚日志</strong> 中的信息来撤销所有更改，原理是对执行的语句进行一次反操作，以确保数据的原子性。</li></ul><p><strong>一致性</strong></p><ul><li>是 ACID 的目的，也就是说，只要保证了原子性、隔离性和持久性，自然也就保证了数据的一致性。</li></ul><p><strong>隔离性</strong></p><ul><li>是数据库通过设置 <strong>事务隔离级别</strong>（如读未提交、读已提交、可重复读、串行化）来控制事务间的交互来保证，可以防止诸如脏读、不可重复读和幻读等并发问题。</li><li>比如 InnoDB 存储引擎使用 MVCC 机制来处理并发事务，确保每个事务都有自己的数据版本，可以有效确保事务的隔离性。</li></ul><p><strong>持久性</strong></p><ul><li>由存储引擎写入磁盘来确保。即使在系统崩溃之后，已提交事务的更改也不会丢失。</li><li>InnoDB 使用 <strong>重做日志</strong> 来记录数据的更改。当事务进行写操作时，InnoDB 首先会将修改写入 <strong>重做日志</strong>，而并不会立即修改磁盘上的数据文件，这种写入方式被称为 <strong>日志预写技术</strong>。</li><li>系统崩溃时，由于数据可能还没有被真正写入数据文件，但修改操作已经写入了 <strong>重做日志</strong>，因此系统可以在启动时会检查 <strong>重做日志</strong> 和 <strong>二进制日志</strong> 的区别，来重新执行这些更改或者回滚这些更改，以确保数据的持久性。</li></ul><h4 id="事务的隔离级别有哪些-mysql-的默认隔离级别呢" tabindex="-1">事务的隔离级别有哪些？MySQL 的默认隔离级别呢 <a class="header-anchor" href="#事务的隔离级别有哪些-mysql-的默认隔离级别呢" aria-label="Permalink to &quot;事务的隔离级别有哪些？MySQL 的默认隔离级别呢&quot;">​</a></h4><p>事务的隔离级别有四种，分别是读未提交、读已提交、可重复读、串行化，其中：</p><ul><li><strong>读未提交</strong>：指一个事务可以读取到别的事务还没提交的更改，这种情况下，可能发生脏读、不可重复读和幻读现象；</li><li><strong>读已提交</strong>：指一个事务只能读取到别的事务已经提交的更改，这种情况下，脏读的问题被解决了，但仍可能发生不可重复读和幻读现象；</li><li><strong>可重复读</strong>：指一个事务执行过程中看到的数据，跟这个事务启动时看到的数据永远是一致的，不管别的事务是否对数据做了修改，这种情况下，脏读和不可重复读的问题被解决了，但仍可能发生幻读现象。</li><li><strong>串行化</strong>：会对数据加上读写锁，在多个事务对这条数据进行读写操作时，如果发生了冲突，后访问的事务必须等前一个事务执行完成，才能继续执行，这种情况下，脏读、不可重复读和幻读现象都被解决了。</li></ul><p>上述几种隔离机制，级别越高，安全性就越强，但性能就越低。</p><p>InnoDB 的默认隔离级别是 <strong>可重复读</strong>。</p><h4 id="四种隔离机制的实现" tabindex="-1">四种隔离机制的实现 <a class="header-anchor" href="#四种隔离机制的实现" aria-label="Permalink to &quot;四种隔离机制的实现&quot;">​</a></h4><p>对于 <strong>读未提交</strong> 隔离级别的事务来说，因为可以读到未提交事务修改的数据，所以直接读取最新的数据就好了。</p><p>对于 <strong>串行化</strong> 隔离级别的事务来说，通过加读写锁的方式来避免并行访问。</p><p>对于 <strong>读已提交</strong> 和 <strong>可重复读</strong> 隔离级别的事务来说，它们是通过 MVCC（多版本并发控制）和 Read View （一致性视图）来实现的，它们的区别在于创建 Read View 的时机不同。</p><p><strong>读提交</strong> 是在事务期间 <strong>每个语句执行前</strong> 都会重新生成一个 Read View，这样就能保证自己每次都能读到其它事务提交的数据。</p><p>而 <strong>可重复读</strong> 是 <strong>启动事务时</strong> 生成一个 Read View，然后整个事务期间都在用这一个 Read View，这样就能保证后续读取的结果完全一致。</p><h4 id="什么是脏读-不可重复读-幻读呢" tabindex="-1">什么是脏读，不可重复读，幻读呢 <a class="header-anchor" href="#什么是脏读-不可重复读-幻读呢" aria-label="Permalink to &quot;什么是脏读，不可重复读，幻读呢&quot;">​</a></h4><ul><li><strong>脏读</strong>：如果事务 A 和 B 交替执行，事务 A 读取到了事务 B 未提交的数据，这就是 <strong>脏读</strong>。在这种情况下，如果事务 B 回滚了，那么 A 所读到的数据就是不合法的。</li><li><strong>不可重复读</strong>：在一个事务内多次读取同一条数据，如果出现前后两次读到的数据不一样的情况，就意味着发生了 <strong>不可重复读</strong> 现象。</li><li><strong>幻读</strong>：事务 A 查询一个范围的结果集，之后另一个并发事务 B 往这个范围中插入或者删除了数据，并悄悄地提交。然后事务 A 再次查询相同的范围，两次读取得到的结果集就不一样了，这就是 <strong>幻读</strong>。</li></ul><h4 id="mvcc-了解吗-怎么实现的" tabindex="-1">MVCC 了解吗？怎么实现的？ <a class="header-anchor" href="#mvcc-了解吗-怎么实现的" aria-label="Permalink to &quot;MVCC 了解吗？怎么实现的？&quot;">​</a></h4><p>MVCC 也就是是多版本并发控制，简单来说就是通过 <strong>维护数据历史版本</strong>，从而解决并发访问情况下的 <strong>读一致性</strong> 问题。</p><p>关于它的实现，主要依赖于四个机制：<strong>隐式字段、回滚日志、版本链和 Read View（一致性视图）</strong>：</p><ul><li>在 InnoDB 存储引擎中，每个聚簇索引记录中都有两个隐藏的列： <strong>事务 ID</strong> 和 <strong>回滚指针</strong><ul><li>当当前事务对某条聚簇索引记录进行修改时，就会 <strong>把当前事务的 id 记录在新记录的事务 ID 隐藏列里</strong>；</li><li>同时会把旧版本的记录写入到 <strong>回滚日志</strong> 中，然后 <strong>令新记录的回滚指针指向每一个旧记录</strong>，使我们可以通过它来找到修改前的记录。</li></ul></li><li>通过这种机制，我们等于是把这条记录的回滚日志串联了起来，形成了一个 <strong>版本链</strong>，版本链的头节点就是当前记录最新的值。</li></ul><p>但这样还不够。</p><p>InnoDB 为了确定在 <strong>读已提交</strong> 和 <strong>可重复读</strong> 隔离级别下，版本链中哪个版本是能被当前事务读取的，就引入了 Read View。</p><p>Read View 有四个重要的字段：</p><ul><li>活跃事务 id 列表：保存的就在创建当前 Read View 时，数据库中 <strong>已启动但没提交</strong> 的 <strong>事务 id 列表</strong></li><li>活跃事务列表中最小的事务 id</li><li>全局事务中最大的事务 id + 1</li><li>创建该 Read View 的事务的 id</li></ul><p>有了 ReadView ，这样在访问某条记录时，就可以 <strong>按照一定的规则</strong> 来判断记录的某个版本是否对当前事务可见，这些规则中最重要的是 <strong>活跃事务的版本是不可见的</strong>。</p><p>如果某个版本对当前事务不可见的话，那就顺着版本链找前一个版本的数据继续判断，直到找到可见的版本。</p><p>对于 <strong>读已提交</strong> 和 <strong>可重复读</strong> 隔离级别的事务来说，它们是通过 MVCC（多版本并发控制）和 Read View （一致性视图）来实现的，它们的区别在于创建 Read View 的时机不同。</p><p><strong>读提交</strong> 是在事务期间 <strong>每个语句执行前</strong> 都会重新生成一个 Read View，这样就能保证自己每次都能读到其它事务提交的数据。</p><p>而 <strong>可重复读</strong> 是 <strong>启动事务时</strong> 生成一个 Read View，然后整个事务期间都在用这一个 Read View，这样就能保证后续读取的结果完全一致。</p><h3 id="存储引擎" tabindex="-1">存储引擎 <a class="header-anchor" href="#存储引擎" aria-label="Permalink to &quot;存储引擎&quot;">​</a></h3><h4 id="mysql-有哪些常见存储引擎-区别是什么" tabindex="-1">MySQL 有哪些常见存储引擎，区别是什么 <a class="header-anchor" href="#mysql-有哪些常见存储引擎-区别是什么" aria-label="Permalink to &quot;MySQL 有哪些常见存储引擎，区别是什么&quot;">​</a></h4><p>MySQL 之前的默认存储引擎是 MylSAM，现在改成了 InnoDB。</p><p>MyISAM 只有表 <strong>锁</strong>，而 InnoDB 除了表锁还支持行锁，在并发情况下性能更好。</p><p>MyISAM 不提供 <strong>事务</strong> 支持，而InnoDB 提供事务支持，实现了四种隔离级别。</p><p>MyISAM 不支持 <strong>外键</strong>，而 InnoDB 支持外键，一定程度上可以维护数据一致性，但对性能有一定损耗。</p><h3 id="锁" tabindex="-1">锁 <a class="header-anchor" href="#锁" aria-label="Permalink to &quot;锁&quot;">​</a></h3><h4 id="mysql-中有哪几种锁" tabindex="-1">MySQL 中有哪几种锁 <a class="header-anchor" href="#mysql-中有哪几种锁" aria-label="Permalink to &quot;MySQL 中有哪几种锁&quot;">​</a></h4><p>如果按细粒度划分，主要有两种：</p><ul><li>表锁：细粒度大，发生锁冲突概率高，并发度低</li><li>行锁：细粒度小，发生锁冲突的概率低，并发度高，行锁中又分为三种： <ul><li>记录锁：用来锁定单个行记录</li><li>间隙锁：锁定一个 <strong>开区间</strong> 范围，不包括行记录本身。</li><li>临键锁：是 <strong>记录锁和间隙锁的结合</strong>，锁定一个 <strong>左开右闭区间</strong> 范围，包含行记录本身</li><li>间隙锁和临键锁由于可以锁范围，所以可以解决 <strong>幻读</strong> 问题</li></ul></li></ul><p>如果按照兼容性，主要有两种：</p><ul><li>共享锁：也叫读锁，事务在读取记录的时候获取共享锁，允许多个事务同时获取</li><li>排他锁：也叫写锁，排他锁是阻塞的，事务在修改记录的时候获取排他锁，不允许多个事务同时获取。如果一个记录已经被加了排他锁，那其他事务不能再对这条事务加任何类型的锁</li></ul><p>此外还有意向锁和插入意向锁。</p><h4 id="mysql-的乐观锁和悲观锁" tabindex="-1">MySQL 的乐观锁和悲观锁 <a class="header-anchor" href="#mysql-的乐观锁和悲观锁" aria-label="Permalink to &quot;MySQL 的乐观锁和悲观锁&quot;">​</a></h4><ul><li><p>**悲观锁 **认为被它保护的数据是极其不安全的，每时每刻都有可能被改动，一个事务拿到悲观锁后，其他任何事务都不能对该数据进行修改，只能等待锁被释放才可以执行。</p><p>MySQL 数据库中的行锁，表锁，读锁，写锁均为悲观锁。</p></li><li><p><strong>乐观锁</strong> 认为数据的变动不会太频繁。</p><p>乐观锁通常是通过在表中增加一个 <strong>版本号(version)</strong> 或 <strong>时间戳(timestamp)</strong> 来实现，其中，版本号最为常用。</p><p>事务在从数据库中取数据时，会将该数据的 <strong>版本号</strong> 也取出来，当事务对数据变动完毕想要将其更新到表中时，会将之前取出的<strong>版本号</strong>与数据中最新的 <strong>版本号</strong> 相对比：</p><ul><li>如果二者相同，那么说明在数据变动期间，没有其他事务对数据进行过修改，此时，就允许将数据更新到表中，并且修改时 <strong>版本号</strong> 会加 1，以此来表明数据已经变动。</li><li>如果二者不相同，那么说明在数据变动期间，数据被其他事务修改了，此时不允许将数据更新到表中，一般的处理办法是通知用户让其重新操作。</li></ul></li></ul><p><strong>不同于悲观锁，乐观锁通常是由开发者自己实现的</strong>。</p><h3 id="两阶段提交" tabindex="-1">两阶段提交 <a class="header-anchor" href="#两阶段提交" aria-label="Permalink to &quot;两阶段提交&quot;">​</a></h3><p>两阶段提交把单个事务的提交分为了 <strong>准备阶段</strong> 和 <strong>提交阶段</strong>：</p><ol><li>先写入 <strong>重做日志</strong>，并将记录标记为 <strong>准备状态</strong>。</li><li>再写入二进制日志。</li><li>最后修改 <strong>重做日志</strong>，并将记录标记为 <strong>提交状态</strong>。</li></ol><p>为什么要采用两阶段提交呢，因为事务提交时，<strong>重做日志</strong> 和 <strong>二进制日志</strong> 都要持久化到磁盘，但是这两个是独立的操作。</p><p>如果不采用两阶段提交的方式，而是采用“单阶段”进行提交，也就是要么先写入 <strong>重做日志</strong>，后写入 <strong>二进制日志</strong>；要么先写入 <strong>二进制日志</strong>，后写入 <strong>重做日志</strong>。</p><p>那么这两种方式都会导致原先数据库的状态和被恢复后的数据库的状态不一致。</p><p>举个例子：</p><ul><li><p><strong>如果在写入重做日志后系统崩溃了，而二进制日志还没来得及写入</strong>。MySQL 重启后，通过 <strong>重做日志</strong> 能将数据库中更新为新值，但在 <strong>二进制日志</strong> 里没有记录这条更新语句，这会导致在 <strong>主从架构</strong> 中，二进制日志会被复制到从库，从库中只会有旧值，与主库的值会不一致；</p></li><li><p><strong>如果在写入二进制日志后系统崩溃了，而重做日志还没有来得及写入</strong>。MySQL 重启后，此事务无效，所以回滚后数据库中依然是旧值，而 <strong>二进制日志</strong> 里面记录了这条更新语句，这会导致在 <strong>主从架构</strong> 中，二进制日志会被复制到从库，从库中只会有新值，与主库的值也会不一致；</p></li></ul><p>综上所述，MySQL 为了避免出现两份日志之间的逻辑不一致的问题，使用了 <strong>两阶段提交</strong> 来解决。</p><p>在这种方案下：</p><ul><li>写入 <strong>重做日志</strong>，处于 <strong>准备状态</strong> 的时候系统崩溃了，此时由于二进制日志还没写，<strong>重做日志</strong> 处于准备状态，所以崩溃恢复的时候，这个事务会回滚，此时 <strong>二进制日志</strong> 还没写，所以也不会传到备库。</li><li>假设写完 <strong>二进制日志</strong> 之后崩溃了，此时 <strong>重做日志</strong> 中的日志处于准备状态，那么恢复的时候，首先检查 <strong>二进制日志</strong> 中的事务是否存在并且完整，如果存在且完整，则直接提交事务，如果不存在或者不完整，则回滚事务。</li><li>假设 <strong>重做日志</strong> 处于 <strong>提交状态</strong> 的时候崩溃了，那么重启后的处理方案跟刚才一样。</li></ul><p>由此可见，两阶段提交确实能够确保数据的一致性。</p><h2 id="redis" tabindex="-1">Redis <a class="header-anchor" href="#redis" aria-label="Permalink to &quot;Redis&quot;">​</a></h2><h3 id="redis-为什么快" tabindex="-1">Redis 为什么快 <a class="header-anchor" href="#redis-为什么快" aria-label="Permalink to &quot;Redis 为什么快&quot;">​</a></h3><p>Redis 的快主要有 4 个原因：</p><ol><li><strong>基于内存的数据存储</strong>：Redis 将数据存储在内存当中，使得数据的读写操作避开了 <strong>磁盘 I/O</strong>。而内存的访问速度远超硬盘，这是 Redis 读写速度快的根本原因。</li><li><strong>单线程模型</strong>：Redis 使用单线程模型来处理客户端的请求，这意味着在任何时刻只有一个命令在执行。这样就避免了 <strong>线程切换</strong> 和 <strong>锁竞争</strong> 带来的消耗。</li><li><strong>IO 多路复⽤</strong>：Redis 通过 <strong>IO 多路复用程序</strong> 来监听多个 socket，一旦有请求到达，就会交给 Redis 处理，让 Redis 不需要额外创建多余的线程来监听大量连接，降低了资源的消耗。</li><li><strong>高效的数据结构</strong>：Redis 提供了多种高效的数据结构，如字符串（String）、列表（List）、集合（Set）、有序集合（ZSet）等，这些数据结构经过了高度优化，能够支持快速的数据操作。</li></ol><h3 id="redis-的缓存作用" tabindex="-1">Redis 的缓存作用 <a class="header-anchor" href="#redis-的缓存作用" aria-label="Permalink to &quot;Redis 的缓存作用&quot;">​</a></h3><p>用户的数据一般都是存储于数据库里，也就是落在磁盘上的，磁盘的读写速度是很慢的。</p><p>当用户的请求，都访问数据库的话，请求数量一旦多了，数据库就很容易奔溃，所以为了避免用户频繁访问数据库，我们一般会用 Redis 作为缓存层。</p><p>因为 Redis 是内存数据库，内存的读写速度比硬盘快好几个数量级，我们可以将数据库的一些数据缓存在 Redis 里，这样可以大大提高系统性能。</p><h3 id="常见数据类型和应用场景" tabindex="-1">常见数据类型和应用场景 <a class="header-anchor" href="#常见数据类型和应用场景" aria-label="Permalink to &quot;常见数据类型和应用场景&quot;">​</a></h3><p>Redis 常见的有五种数据类型：<strong>String（字符串），Hash（哈希），List（列表），Set（集合）、Zset（有序集合）</strong>。</p><img src="'+l+'" alt="三分恶面渣逆袭：Redis基本数据结构" style="zoom:80%;"><p><strong>字符串</strong> 是最基础的数据结构，value 可以是：字符串、数字、甚至是二进制（图片、音频、视频）数据</p><p>String 常用于：</p><ul><li>缓存对象</li><li>计数功能</li><li>共享 Session 信息</li><li>分布式锁</li></ul><p><strong>哈希</strong> 的 value 是一个 Map 集合</p><p>Hash 常用于：</p><ul><li>缓存对象</li></ul><p><strong>List</strong> 是一个简单的字符串列表，按照插入顺序排序。可以添加一个元素到列表的头部（左边）或者尾部（右边）。</p><p>List 常用于：</p><ul><li>消息队列</li></ul><p><strong>Set</strong> 是字符串的集合，它的特点是无序、不可重复、支持并交差操作。</p><p>Set 常用于：</p><ul><li>点赞</li><li>共同关注</li></ul><p><strong>Zset</strong> 是有序集合，比 Set 多了一个按 <strong>分值</strong> 排序的功能。</p><p>Zset 常用于：</p><ul><li>排行榜</li><li>姓名排序</li><li>电话排序</li></ul><h3 id="redis-如何实现数据不丢失" tabindex="-1">Redis 如何实现数据不丢失 <a class="header-anchor" href="#redis-如何实现数据不丢失" aria-label="Permalink to &quot;Redis 如何实现数据不丢失&quot;">​</a></h3><p>Redis 的读写操作都是在内存中，所以性能才会高，但是当 Redis 重启后，内存中的数据就会丢失。为了保证 Redis 的数据不会丢失，Redis 采用了 <strong>数据持久化</strong> 的机制，它会把数据存储到磁盘里，这样在 Redis 重启时就能恢复原有的数据。</p><h3 id="持久化" tabindex="-1">持久化 <a class="header-anchor" href="#持久化" aria-label="Permalink to &quot;持久化&quot;">​</a></h3><p>Redis 主要有两种数据持久化的方式：</p><ul><li><strong>AOF 日志</strong>：每执行一条写操作命令，就把该命令以追加的方式写入到一个 AOF 文件中。在 Redis 重启时，会读取该文件中记录的命令，然后逐个执行来进行数据恢复。</li><li><strong>RDB 快照</strong>：每隔一段时间将 Redis 在某一时刻的数据状态保存到磁盘的一个 RDB 文件中。在 Redis 重启时，直接将 RDB 文件读入内存就可以了。</li></ul><h4 id="rdb-和-aof-各自有什么优缺点" tabindex="-1">RDB 和 AOF 各自有什么优缺点 <a class="header-anchor" href="#rdb-和-aof-各自有什么优缺点" aria-label="Permalink to &quot;RDB 和 AOF 各自有什么优缺点&quot;">​</a></h4><p>RDB：</p><ol><li><strong>文件小</strong>：只有一个紧凑的二进制文件，非常适合备份、全量复制的场景。</li><li><strong>恢复速度快</strong>：RDB 恢复数据的速度远远快于 AOF 的方式。</li><li><strong>实时性低</strong>：RDB 是间隔一段时间进行持久化，没法做到实时持久化。如果在这一间隔内发生故障，数据会丢失。</li></ol><p>AOF：</p><ol><li><strong>文件大</strong></li><li><strong>恢复速度慢</strong></li><li><strong>实时性强</strong>：AOF 是每执行一条写操作命令就追加到文件中，比较快。</li></ol><h3 id="内存淘汰策略" tabindex="-1">内存淘汰策略 <a class="header-anchor" href="#内存淘汰策略" aria-label="Permalink to &quot;内存淘汰策略&quot;">​</a></h3><p>在 Redis 的运行内存达到了 <strong>最大限制</strong> 时，就会触发 <strong>内存淘汰机制</strong>。</p><p>Redis 的内存淘汰策略共有 8 种，这八种策略大体分为 <strong>不进行数据淘汰</strong> 和 <strong>进行数据淘汰</strong> 两类。</p><p><strong>不进行数据淘汰的策略</strong>：</p><ul><li>当内存不足以容纳新写入数据时会返回错误，但允许读数据和删除数据。</li></ul><p><strong>进行数据淘汰的策略</strong>：</p><p>针对 <strong>进行数据淘汰</strong> 这一类策略，又可以细分为 <strong>在设置了过期时间的数据中进行淘汰</strong> 和 <strong>在所有数据范围内进行淘汰</strong> 这两类。</p><p>在设置了过期时间的数据中进行淘汰：</p><ul><li><strong>随机</strong> 淘汰设置了过期时间的任意数据；</li><li>淘汰最早过期的数据。</li><li>淘汰所有设置了过期时间的数据中，<strong>最久没使用</strong> 的数据；</li><li>淘汰所有设置了过期时间的数据中，<strong>最少使用</strong> 的数据；</li></ul><p>在所有数据范围内进行淘汰：</p><ul><li><strong>随机</strong> 淘汰任意数据;</li><li>淘汰所有数据中 <strong>最久没使用</strong> 的数据；</li><li>淘汰所有数据中 <strong>最少使用</strong> 的数据。</li></ul><h3 id="缓存雪崩" tabindex="-1">缓存雪崩 <a class="header-anchor" href="#缓存雪崩" aria-label="Permalink to &quot;缓存雪崩&quot;">​</a></h3><p>通常我们为了保证缓存中的数据与数据库中的数据一致性，会给 Redis 里的数据设置过期时间，当缓存数据过期后，用户访问的数据如果不在缓存里，业务系统需要重新生成缓存，因此就会访问数据库，并将数据更新到 Redis 里。</p><p>那么，当 <strong>大量缓存数据在同一时间过期或者 Redis 故障宕机</strong> 时，如果此时有大量的用户请求，都无法在 Redis 中处理，于是全部请求都直接访问数据库，从而导致数据库的压力骤增，严重的会造成数据库宕机，从而形成一系列连锁反应，甚至整个系统都会崩溃，这就是 <strong>缓存雪崩</strong> 的问题。</p><p><strong>处理措施</strong>：</p><p>针对大量数据同时过期而引发的缓存雪崩问题，常见的应对方法有两种：</p><ul><li><strong>均匀设置过期时间</strong>：为了避免大量的缓存在同一时间过期，可以把不同的 key 过期时间随机生成，避免过期时间太过集中。</li><li><strong>后台更新缓存</strong>：保证数据一直不会过期，并将更新缓存的工作交由后台线程定时执行。</li></ul><p>针对 Redis 故障宕机而引发的缓存雪崩问题，常见的应对方法有三种：</p><ul><li><strong>服务熔断</strong>：也就是暂时停止业务服务访问缓存系统，直接返回错误，防止数据库宕机。</li><li><strong>请求限流</strong>：只将少部分请求发送到数据库进行处理，其余的请求直接拒绝服务。</li><li><strong>构建 Redis 集群</strong>：如果 Redis 缓存的主节点故障宕机，<strong>从节点</strong> 可以切换成为 <strong>主节点</strong>，继续提供缓存服务。</li></ul><h3 id="缓存击穿" tabindex="-1">缓存击穿 <a class="header-anchor" href="#缓存击穿" aria-label="Permalink to &quot;缓存击穿&quot;">​</a></h3><p>我们的业务通常会有几个数据会被频繁地访问，这类被频地访问的数据被称为热点数据。</p><p>如果缓存中的 <strong>某个热点数据过期</strong>了，此时大量的请求访问了该热点数据，就无法从缓存中读取，直接访问数据库，数据库很容易就被高并发的请求冲垮，这就是**缓存击穿 **的问题。</p><p><strong>处理措施</strong>：</p><p>应对缓存击穿可以采取两种方案：</p><ul><li><strong>互斥锁方案</strong>：⽐如请求查询 A，发现缓存中没有，对 A 这个 key 加锁，同时去数据库查询数据，写⼊缓存，再返回给⽤户，这样后⾯的请求就可以从缓存中拿到数据了。</li><li><strong>后台更新缓存</strong>：保证数据一直不会过期，并将更新缓存的工作交由后台线程定时执行。</li></ul><h3 id="缓存穿透" tabindex="-1">缓存穿透 <a class="header-anchor" href="#缓存穿透" aria-label="Permalink to &quot;缓存穿透&quot;">​</a></h3><p>当用户要要查询一个 <strong>既不在缓存中，也不在数据库中</strong> 的数据，这样的请求每次都会直接打到数据库，就好像缓存不存在一样，导致数据库的压力骤增，这就是 <strong>缓存穿透</strong> 的问题。</p><p>缓存穿透的发生一般有这两种情况：</p><ul><li><strong>业务代码问题</strong>：缓存中的数据和数据库中的数据都被误删除了，所以导致缓存和数据库中都没有数据；</li><li><strong>黑客恶意攻击</strong>：故意大量访问某些读取不存在数据的业务；</li></ul><p>应对缓存穿透的方案，常见的方案有三种。</p><ul><li><strong>限制非法请求</strong>：如果判断出是恶意请求就直接返回错误，避免进一步访问缓存和数据库。</li><li><strong>缓存空值或者默认值</strong>：可以针对查询的数据，在缓存中设置一个空值或者默认值，这样后续请求就可以从缓存中读取到空值或者默认值，而不会继续查询数据库。</li><li><strong>使用布隆过滤器</strong>：可以在写入数据库数据时，使用布隆过滤器做个标记，然后在用户请求到来时，业务线程确认缓存失效后，可以查询布隆过滤器来快速判断数据是否存在，如果不存在，就不用查询数据库了。这样即使发生了缓存穿透，请求只会查询 Redis 和布隆过滤器，而不会查询数据库，保证了数据库能正常运行，Redis 自身也是支持布隆过滤器的。</li></ul><h3 id="分布式锁" tabindex="-1">分布式锁 <a class="header-anchor" href="#分布式锁" aria-label="Permalink to &quot;分布式锁&quot;">​</a></h3><p>分布式锁是用于分布式环境下并发控制的一种机制，用于控制某个资源在同一时刻只能被一个应用所使用。</p><p>Redis 本身可以被多个客户端共享访问，正好可以用来保存分布式锁，而且 Redis 的读写性能高，可以应对高并发的锁操作场景。</p><p>Redis 的 SET 命令有个 NX 参数可以实现 <strong>key不存在才插入</strong>，这是一个原子操作，所以可以用它来实现分布式锁：</p><ul><li>如果 key 不存在，则插入成功，可以用来表示加锁成功；</li><li>如果 key 存在，则插入失败，可以用来表示加锁失败。</li></ul><p>锁变量需要设置过期时间，以免客户端拿到锁后发生异常，导致锁一直无法释放，所以在执行 SET 命令时要设置其过期时间；</p><p>锁变量的值需要能区分来自不同客户端的加锁操作，以免在释放锁时，出现误释放操作，所以在执行 SET 命令时，要设置一个客户端 id；</p><p>解锁的时候，先判断锁的客户端 id 是否为当前客户端，是的话，就将此键删除，表示解锁成功。</p><p>解锁过程包含两个操作，所以需要 Lua 脚本来保证解锁操作的原子性。</p><p><strong>这样一来，就通过使用 SET 命令和 Lua 脚本在 Redis 单节点上完成了分布式锁的加锁和解锁。</strong></p><h2 id="spring" tabindex="-1">Spring <a class="header-anchor" href="#spring" aria-label="Permalink to &quot;Spring&quot;">​</a></h2><h3 id="ioc" tabindex="-1">IoC <a class="header-anchor" href="#ioc" aria-label="Permalink to &quot;IoC&quot;">​</a></h3><p><strong>IoC</strong>，也就是 <strong>控制反转</strong>，指的是由容器来控制对象的生命周期。</p><p>以前是我们想要什么就自己创建什么，现在是我们需要什么容器就帮我们送来什么。</p><p>控制对象生命周期的不再是引用它的对象，而是容器，这就叫 <strong>控制反转</strong>。</p><p>之所以要用 IoC，是为了降低对象之间的 <strong>耦合度</strong>，<strong>提升开发效率</strong>。</p><p>在实际项目中一个 Service 类可能依赖了很多其他的类，假如我们需要实例化这个 Service，可能需要手动创建 Service 类依赖的每个对象及其依赖的对象，这个过程通常是递归和繁琐的。</p><p>对于复杂的依赖关系，手动管理这些依赖将会非常困难和容易出错。</p><p>而且如果多处都需要实例化同一个 Service 类，我们可能不得不重复相同的依赖实例化代码，这降低了代码的可维护性。</p><p>相比之下，使用 IoC 的话，容器可以自动管理这些依赖关系，开发者只需声明依赖项，由 IoC 容器负责实例化并注入所需的依赖。</p><p>开发者在需要的地方直接引用就行了，这样就可以将更多的精力集中在 <strong>业务逻辑</strong> 上，而不用花费时间来处理对象的创建和依赖的管理上。</p><h3 id="aop" tabindex="-1">AOP <a class="header-anchor" href="#aop" aria-label="Permalink to &quot;AOP&quot;">​</a></h3><p>AOP，也就是面向切面编程。</p><p>简单说，就是把一些业务逻辑中的相同代码抽取到一个独立的模块中，让业务逻辑更加清爽。</p><p>举个例子，假如我们现在需要在业务代码开始前进行参数校验，在结束后打印日志，该怎么办呢？</p><p>我们可以把 <strong>日志记录</strong> 和 <strong>数据校验</strong> 这两个功能抽取出来，形成一个切面，然后在业务代码中引入这个切面，业务代码不用关心这些通用逻辑，只需要关心自己的业务实现，这样就可以实现业务逻辑和通用逻辑的分离。</p><p>Spring 的 AOP 是通过 <strong>动态代理</strong> 来实现的，它允许我们在运行时动态地创建代理对象，而无需在编译时就确定代理对象的类型。</p><p>动态代理主要有两种方式：JDK 动态代理和 CGLIB 代理。</p><h3 id="动态代理" tabindex="-1">动态代理 <a class="header-anchor" href="#动态代理" aria-label="Permalink to &quot;动态代理&quot;">​</a></h3><p>Spring 的 AOP 是通过 <strong>动态代理</strong> 来实现的，它允许我们在运行时动态地创建代理对象，而无需在编译时就确定代理对象的类型。</p><p>动态代理主要有两种方式：JDK 动态代理和 CGLIB 代理。</p><p><strong>JDK 动态代理</strong></p><p>JDK 动态代理是基于 <strong>接口</strong> 的代理方式：它要求 <strong>目标对象必须实现一个或多个接口</strong>，代理对象不是直接继承自目标对象，而是实现了与目标对象相同的接口。</p><p><strong>CGLIB 动态代理</strong></p><p>CGLIB 动态代理是基于 <strong>继承</strong> 的代理方式：它不需要接口，而是通过在运行时生成目标对象的 <strong>子类</strong> 来创建代理对象，并在子类中覆盖方法。</p><p>在这两种方式的选择上，</p><ul><li><strong>基于接口还是类</strong>：如果被代理的对象没有实现任何接口，则只能使用 CGLIB 代理。如果目标对象实现了接口，则推荐使用 JDK 动态代理。</li><li><strong>性能考虑</strong>：如果性能是一个重要因素，而你的使用场景主要是调用代理方法，则 CGLIB 可能是更好的选择。虽然CGLIB在创建代理对象时比JDK动态代理慢，但在调用代理方法时通常会更快。</li><li><strong>依赖考虑</strong>：如果不想引入额外的库，那么JDK动态代理是更好的选择，因为它是基于Java原生API实现的。</li></ul><h3 id="循环依赖" tabindex="-1">循环依赖 <a class="header-anchor" href="#循环依赖" aria-label="Permalink to &quot;循环依赖&quot;">​</a></h3><p>在 Spring 中，循环依赖是指两个或多个bean相互依赖对方，形成了一个闭环。</p><p>这种情况在Spring的依赖注入过程中可能会引发问题，因为在创建这些 bean 的实例时，每个 bean 的实例化又依赖于其他 bean 的创建，导致无法完成任何一个 bean 的实例化过程。</p><p>循环依赖主要在以下三种场景中出现：</p><ol><li><strong>构造器注入</strong>：当两个或多个 bean 通过构造函数相互注入对方时，会直接导致循环依赖的问题。因为在调用构造函数创建 bean 实例之前，需要先实例化其依赖的 bean，这在循环依赖的情况下是不可能完成的。</li><li><strong>Setter注入</strong>：当 bean 通过 setter 方法或字段注入相互依赖时，Spring 可以通过三级缓存来解决循环依赖的问题，因为 bean 可以在设置完最初的属性后被部分初始化，然后提供给其他 bean 使用，最后完成其余的依赖注入。</li><li><strong>方法注入</strong>：当 bean 之间的依赖关系通过方法调用来实现时，循环依赖也可能出现，但这种情况比较少见。</li></ol><p>Spring 容器通过使用三级缓存处理单例作用域 bean 的循环依赖：</p><ol><li><strong>一级缓存</strong>：用于存储 <strong>完全初始化完成</strong> 的 bean 实例。</li><li><strong>二级缓存</strong>：存储早期的 bean 引用，即 <strong>已经实例化但尚未填充属性</strong> 的 bean。</li><li><strong>三级缓存</strong>：存储 bean 工厂对象，用于 <strong>生成 bean 的早期引用</strong>。</li></ol><p>当 Spring 创建一个 bean 时，它首先创建一个原始的 bean 实例，然后将一个指向这个实例的引用放入三级缓存中。如果在填充属性的过程中遇到了对另一个 bean 的依赖，并且这个依赖又间接或直接依赖于原始 bean，Spring 会使用三级缓存中的引用来解决这个循环依赖。一旦原始 bean 实例的所有属性都被填充完毕，它就会被移动到一级缓存中，供应用程序使用。</p><p>注意：</p><ul><li>Spring 只能解决单例 bean 之间的循环依赖问题。</li><li>对于原型作用域的 bean，Spring 不处理循环依赖，因为每次请求原型 bean 都会创建一个新实例。</li><li>构造器注入的循环依赖不能被 Spring 解决，因为它需要在构造器调用之前解决依赖，这在循环依赖的情况下是做不到的。因此，推荐使用 setter 注入或者字段注入来避免这种情况。</li></ul><p>避免循环依赖的最好方法是在代码编写的时候就注意，不要引入循环依赖。</p>',404),p=[g];function h(d,c,u,b,k,q){return t(),o("div",null,p)}const f=r(e,[["render",h]]);export{y as __pageData,f as default};
